import { useState } from 'react';
import { useNavigate, Link, NavLink } from 'react-router-dom';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps';
import constFlaskURL from '../consts/constFlaskURL'


function Home() {
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const mapState = {
        center: [55.751574, 37.573856],
        zoom: 10,
        controls: [],
    };

    const handleLogout = async () => {
        setLoading(true);

        try {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) {
                setTimeout(() => {
                navigate('/login');
                }, 1000);
            }
        } catch (err) {
            console.error('Logout error:', err);
        } finally {
            setLoading(false);
        }
    };
    return (
        <div> 
            <div>
                <nav className='navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0'>
                    <div className='container-fluid py-2'>
                        <Link className='navbar-brand fs-3 fw-bold' to='/main'>roads_admin</Link>
                        <div class="btn-group">
                            <button type="button" class="btn btn-info">Пользователь</button>
                            <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                                <span class="visually-hidden">Переключатель выпадающего списка</span>
                            </button>
                            <ul class="dropdown-menu">
                                <li>
                                    <a class="dropdown-item">
                                        <button
                                            onClick={handleLogout} 
                                            className='dropdown-item'
                                            disabled={loading}
                                        >
                                            {loading ? (
                                                <>
                                                    <span className='spinner'></span>
                                                    Выход...
                                                </>
                                            ) : 'Выйти'}
                                        </button>
                                    </a>
                                </li>
                            </ul>
                        </div>
                    </div>
                    <div className='container-fluid bg-dark py-2'>
                        <div className='navbar-nav flex-row'>
                            <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/main' end> Главная </NavLink>
                            <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads' end> Дороги </NavLink>
                            <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/sings' end> Дорожные знаки </NavLink>
                            <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads/sings' end> Знаки на дорогах </NavLink>
                            <div class="collapse navbar-collapse" id="navbarNavDarkDropdown">
                                <ul class="navbar-nav">
                                    <li class="nav-item dropdown">
                                        <a class="nav-link dropdown-toggle" href="#" id="navbarDarkDropdownMenuLink" role="button" data-bs-toggle="dropdown" aria-expanded="false">
                                            Перекрестки
                                        </a>
                                        <ul class="dropdown-menu dropdown-menu-dark" aria-labelledby="navbarDarkDropdownMenuLink">
                                            <li>
                                                <button className='dropdown-item'><NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/crossroads' end>Перекрестки</NavLink></button>
                                                <button className='dropdown-item'><NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/type_crossroads' end>Типы перекрестков</NavLink></button>
                                            </li>
                                        </ul>
                                    </li>
                                </ul>
                            </div>
                        </div>
                    </div>
                </nav>
                <div className='container'>
                    <h1>Интерактивная карта.</h1>
                    <div style={{ width: '100%', height: '500px' }}>
                    <YMaps>
                        <Map 
                            state={mapState} 
                            width="100%" 
                            height="500px"
                        >
                            <Placemark geometry={[55.684758, 37.738521]} />
                        </Map>
                    </YMaps>
                    </div>
                </div>
            </div>
        </div>
    );
}

export default Home;
